int[] parent;

int find(int x) {
    if (parent[x] != x) parent[x] = find(parent[x]);  // path compression kept
    return parent[x];
}

void union(int x, int y) {
    int rootX = find(x), rootY = find(y);
    if (rootX != rootY) parent[rootY] = rootX;   // no rank comparison at all
}
